import{_ as d,o as a,c as r,ag as e}from"./chunks/framework.Vng7Hdlh.js";const p=JSON.parse('{"title":"1. はじめに","description":"","frontmatter":{},"headers":[],"relativePath":"internal/features/01-introduction.md","filePath":"internal/features/01-introduction.md"}'),i={name:"internal/features/01-introduction.md"};function l(o,t,h,n,s,c){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="_1-はじめに" tabindex="-1">1. はじめに <a class="header-anchor" href="#_1-はじめに" aria-label="Permalink to &quot;1. はじめに&quot;">​</a></h1><h2 id="_1-1-poslaとは" tabindex="-1">1.1 POSLAとは <a class="header-anchor" href="#_1-1-poslaとは" aria-label="Permalink to &quot;1.1 POSLAとは&quot;">​</a></h2><p>POSLAは、飲食店向けのクラウド型セルフオーダー＆店舗管理システムです。お客さんがQRコードからスマホで注文し、注文がリアルタイムにキッチンのKDS（Kitchen Display System）へ表示されます。スタッフのハンディ端末やPOSレジとも連携し、メニュー管理・在庫管理・シフト管理・売上レポートまで、店舗運営に必要な機能を一つのシステムでカバーします。</p><p>1つの企業アカウントで複数の店舗を管理できます。本部メニューの一元管理と、店舗ごとの価格・品揃えカスタマイズを両立させているため、チェーン展開や多店舗運営にも対応しています。</p><h2 id="動作環境" tabindex="-1">動作環境 <a class="header-anchor" href="#動作環境" aria-label="Permalink to &quot;動作環境&quot;">​</a></h2><h3 id="推奨ブラウザ" tabindex="-1">推奨ブラウザ <a class="header-anchor" href="#推奨ブラウザ" aria-label="Permalink to &quot;推奨ブラウザ&quot;">​</a></h3><table tabindex="0"><thead><tr><th>ブラウザ</th><th>対応状況</th><th>備考</th></tr></thead><tbody><tr><td>Google Chrome（最新版）</td><td><strong>推奨</strong></td><td>音声コマンド（Web Speech API）はChrome必須</td></tr><tr><td>Safari（最新版）</td><td>対応</td><td>iOS端末のデフォルトブラウザ</td></tr><tr><td>Microsoft Edge（最新版）</td><td>対応</td><td></td></tr><tr><td>Firefox（最新版）</td><td>対応</td><td>音声コマンド非対応</td></tr></tbody></table><h3 id="推奨端末" tabindex="-1">推奨端末 <a class="header-anchor" href="#推奨端末" aria-label="Permalink to &quot;推奨端末&quot;">​</a></h3><table tabindex="0"><thead><tr><th>用途</th><th>推奨端末</th><th>画面サイズ</th></tr></thead><tbody><tr><td>管理ダッシュボード</td><td>PC / タブレット</td><td>10インチ以上推奨</td></tr><tr><td>KDS（キッチンディスプレイ）</td><td>タブレット（10インチ以上）</td><td>横置き推奨</td></tr><tr><td>ハンディPOS</td><td>スマートフォン / 小型タブレット</td><td>5〜8インチ</td></tr><tr><td>POSレジ</td><td>PC / タブレット</td><td>10インチ以上推奨</td></tr><tr><td>セルフオーダー（お客さん）</td><td>お客さんのスマートフォン</td><td>制限なし</td></tr></tbody></table><h3 id="インターネット接続" tabindex="-1">インターネット接続 <a class="header-anchor" href="#インターネット接続" aria-label="Permalink to &quot;インターネット接続&quot;">​</a></h3><p>POSLAはクラウド型のシステムです。常時インターネット接続が必要です。ただし、一時的な接続切断時には「オフライン検知機能」が動作し、画面上部に赤いバナーで警告が表示されます。接続が復旧すると自動的に緑のバナーが表示され、通常動作に戻ります。</p><div class="warning custom-block"><p class="custom-block-title">注意</p><p>オフライン中は新規注文の送信やデータの取得ができません。Wi-Fi環境が不安定な場合は、有線LAN接続またはモバイルルーターのバックアップを推奨します。</p></div><h2 id="ロールの違い" tabindex="-1">ロールの違い <a class="header-anchor" href="#ロールの違い" aria-label="Permalink to &quot;ロールの違い&quot;">​</a></h2><p>POSLAには3つのユーザーロールがあります。ロールによって操作できる機能が異なります。</p><h3 id="オーナー-owner" tabindex="-1">オーナー（owner） <a class="header-anchor" href="#オーナー-owner" aria-label="Permalink to &quot;オーナー（owner）&quot;">​</a></h3><p>テナント全体の管理者です。全店舗に暗黙的にアクセスでき、以下の操作が可能です。</p><ul><li>店舗の追加・編集・削除</li><li>全店舗のユーザーアカウント管理（マネージャー・スタッフの作成）</li><li>クロス店舗レポート（複数店舗の売上を横並び比較）</li><li>ABC分析（売上貢献度によるメニュー分類）</li><li>契約・プラン管理（サブスクリプション）</li><li>決済設定（Stripe Connect）</li><li>統合シフトビュー（全店舗のシフト横断表示、enterpriseプラン）</li><li>外部POS連携（スマレジ）</li><li>AIアシスタント（店舗を選択して分析）</li></ul><p>ログイン後は <strong>オーナーダッシュボード</strong>（owner-dashboard.html）に自動遷移します。</p><h3 id="マネージャー-manager" tabindex="-1">マネージャー（manager） <a class="header-anchor" href="#マネージャー-manager" aria-label="Permalink to &quot;マネージャー（manager）&quot;">​</a></h3><p>割り当てられた店舗の管理者です。以下の操作が可能です。</p><ul><li>メニュー管理（カテゴリ・テンプレート・オーバーライド・限定メニュー・オプション）</li><li>テーブル・フロアマップ管理</li><li>在庫管理（食材・レシピ・棚卸し）</li><li>注文管理（ハンディPOS・テイクアウト）</li><li>KDS操作（キッチンディスプレイ）</li><li>レジ操作（会計・精算）</li><li>レポート閲覧（売上・レジ・回転率・スタッフ評価・併売分析）</li><li>店舗設定（営業時間・税率・支払い方法・ブランディング等）</li><li>スタッフ管理（自店舗のスタッフアカウント作成）</li><li>シフト管理（全機能：テンプレート・カレンダー・勤怠一覧・サマリー・AI提案・ヘルプ要請）</li><li>AIアシスタント（SNS投稿生成・売上分析・競合調査・需要予測）</li><li>監査ログ閲覧</li><li>領収書設定</li></ul><p>ログイン後は <strong>管理ダッシュボード</strong>（dashboard.html）に自動遷移します。</p><h3 id="スタッフ-staff" tabindex="-1">スタッフ（staff） <a class="header-anchor" href="#スタッフ-staff" aria-label="Permalink to &quot;スタッフ（staff）&quot;">​</a></h3><p>割り当てられた店舗の操作担当者です。以下の操作が可能です。</p><ul><li>ハンディPOS（注文入力）</li><li>KDS操作（キッチンディスプレイ）</li><li>レジ操作（会計）</li><li>勤怠打刻（出勤・退勤）</li><li>マイシフト確認（自分のシフト閲覧）</li><li>希望シフト提出</li></ul><p>ログイン後は <strong>管理ダッシュボード</strong>（dashboard.html）に自動遷移します。マネージャー専用のタブ（メニュー管理、レポート等）は非表示になります。</p><div class="tip custom-block"><p class="custom-block-title">1人1アカウントは必須です</p><p>POSLAでは全スタッフに個別のユーザーアカウントを作成してください。「kitchen」「hall」などの共有アカウントは禁止です。監査ログ・勤怠打刻・スタッフ評価・シフト管理の全てが「誰が操作したか」を前提に設計されています。アカウント未作成のスタッフはシフト管理・勤怠の対象外になります。</p></div><h3 id="アカウント作成権限の階層" tabindex="-1">アカウント作成権限の階層 <a class="header-anchor" href="#アカウント作成権限の階層" aria-label="Permalink to &quot;アカウント作成権限の階層&quot;">​</a></h3><table tabindex="0"><thead><tr><th>操作者</th><th>作成できるアカウント</th><th>対象範囲</th></tr></thead><tbody><tr><td>オーナー</td><td>マネージャー、スタッフ</td><td>テナント内の全店舗</td></tr><tr><td>マネージャー</td><td>スタッフのみ</td><td>自分の所属店舗のみ</td></tr><tr><td>スタッフ</td><td>作成権限なし</td><td>—</td></tr></tbody></table><h3 id="プランによる機能制限" tabindex="-1">プランによる機能制限 <a class="header-anchor" href="#プランによる機能制限" aria-label="Permalink to &quot;プランによる機能制限&quot;">​</a></h3><p>POSLAには3つの料金プランがあり、利用できる機能が異なります。</p><table tabindex="0"><thead><tr><th>機能</th><th>standard</th><th>pro</th><th>enterprise</th></tr></thead><tbody><tr><td>セルフオーダー・KDS・ハンディPOS</td><td>✓</td><td>✓</td><td>✓</td></tr><tr><td>フロアマップ・テーブル管理</td><td>✓</td><td>✓</td><td>✓</td></tr><tr><td>基本レポート</td><td>✓</td><td>✓</td><td>✓</td></tr><tr><td>オフライン検知</td><td>✓</td><td>✓</td><td>✓</td></tr><tr><td>在庫管理・AI需要予測</td><td>—</td><td>✓</td><td>✓</td></tr><tr><td>高度レポート（回転率・スタッフ評価・併売分析）</td><td>—</td><td>✓</td><td>✓</td></tr><tr><td>シフト管理・勤怠連携</td><td>—</td><td>✓</td><td>✓</td></tr><tr><td>テイクアウト</td><td>—</td><td>✓</td><td>✓</td></tr><tr><td>多言語対応</td><td>—</td><td>✓</td><td>✓</td></tr><tr><td>決済ゲートウェイ（Square/Stripe）</td><td>—</td><td>✓</td><td>✓</td></tr><tr><td>HQメニュー一括配信</td><td>—</td><td>—</td><td>✓</td></tr><tr><td>店舗間ヘルプ要請</td><td>—</td><td>—</td><td>✓</td></tr><tr><td>統合シフトビュー</td><td>—</td><td>—</td><td>✓</td></tr><tr><td>クロス店舗分析</td><td>—</td><td>—</td><td>✓</td></tr></tbody></table>',32)])])}const u=d(i,[["render",l]]);export{p as __pageData,u as default};
